INSERT INTO `wp_4kb4pz_options` VALUES("2615", "_transient_dash_4077549d03da2e451c8b5f002294ff51", "<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'http://wordpress.org/news/2012/10/wordpress-3-5-beta-2/\' title=\'Two weeks after the first beta, WordPress 3.5 Beta 2 is now available for download and testing. This is software still in development, so we don\'t recommend that you run it on a production site. Set up a test site to play with the new version. To test WordPress 3.5, try the WordPress Beta Tester plugin (you\'ll want \"bleeding [&hellip;]\'>WordPress 3.5 Beta 2</a> <span class=\"rss-date\">October 13, 2012</span><div class=\'rssSummary\'>Two weeks after the first beta, WordPress 3.5 Beta 2 is now available for download and testing. This is software still in development, so we don\'t recommend that you run it on a production site. Set up a test site to play with the new version. To test WordPress 3.5, try the WordPress Beta Tester plugin (you\'ll want \"bleeding [&hellip;]</div></li><li><a class=\'rsswidget\' href=\'http://wordpress.org/news/2012/09/wordpress-3-5-beta-1/\' title=\'I\'m excited to announce the availability of WordPress 3.5 Beta 1. This is software still in development and we really don\'t recommend that you run it on a production site -- set up a test site just to play with the new version. To test WordPress 3.5, try the WordPress Beta Tester plugin (you\'ll want \"bleeding edge nightlies\"). Or you can download [&hellip;]\'>WordPress 3.5 Beta 1 (and a bonus!)</a> <span class=\"rss-date\">September 27, 2012</span><div class=\'rssSummary\'>I\'m excited to announce the availability of WordPress 3.5 Beta 1. This is software still in development and we really don\'t recommend that you run it on a production site -- set up a test site just to play with the new version. To test WordPress 3.5, try the WordPress Beta Tester plugin (you\'ll want \"bleeding edge nightlies\"). Or you can download [&hellip;]</div></li></ul></div>", "no");
