press.com/1.0/comments/wptv.wordpress.com/14095/\" /></a> <img alt=\"\" border=\"0\" src=\"http://stats.wordpress.com/b.gif?host=wordpress.tv&blog=5089392&post=14095&subd=wptv&ref=&feed=1\" width=\"1\" height=\"1\" /><div><a href=\"http://wordpress.tv/2012/10/31/konstantin-kovshenin-settings-api/\"><img alt=\"Konstantin Kovshenin: Settings API\" src=\"http://videos.videopress.com/gU1RRTBd/video-6218437416_std.original.jpg\" width=\"160\" height=\"120\" /></a></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 31 Oct 2012 20:14:28 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"WordPress.tv\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"Weblog Tools Collection: Halloween WordPress Themes\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"http://weblogtoolscollection.com/?p=12171\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/1ycMQl8nQvU/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1289:\"<p>Whether you celebrate Halloween or not, here are three themes to get your blog in the right mood.</p>\n<p><img class=\"alignnone size-full wp-image-12113\" title=\"hauntedhouse\" src=\"http://weblogtoolscollection.com/wp-content/uploads/2012/10/hauntedhouse.jpg\" alt=\"\" width=\"150\" height=\"113\" /></p>\n<p><a href=\"http://wordpress.org/extend/themes/haunted-house\"><strong>Haunted House</strong></a> is a Halloween theme for your blog.</p>\n<p><img class=\"alignnone size-full wp-image-12172\" title=\"monster\" src=\"http://weblogtoolscollection.com/wp-content/uploads/2012/10/monster.jpg\" alt=\"\" width=\"150\" height=\"113\" /></p>\n<p><a href=\"http://carolinethemes.com/2012/10/19/monster/\"><strong>Monster</strong></a> is a Halloween theme with your choice of monster.</p>\n<p><img class=\"alignnone size-full wp-image-12173\" title=\"wickedhalloween\" src=\"http://weblogtoolscollection.com/wp-content/uploads/2012/10/wickedhalloween.jpg\" alt=\"\" width=\"150\" height=\"112\" /></p>\n<p><a href=\"http://emptynestthemes.emptynestheritage.com/2011/10/17/wicked-halloween/\"><strong>Wicked Halloween</strong></a> is a Halloween theme with orange, gold, and black, and despite being dark, appears bright.</p>\n<img src=\"http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/1ycMQl8nQvU\" height=\"1\" width=\"1\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 31 Oct 2012 15:15:12 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"James\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"Ping-O-Matic: Ping-O-Matic: A Simple Way to Draw Traffic\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"http://blog.pingomatic.com/?p=50\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"http://blog.pingomatic.com/2012/10/31/ping-o-matic-a-simple-way-to-draw-traffic/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4425:\"<p>With a WordPress blog, you have a variety of tools to not only create content, but to share it and get your newest, freshest stuff out to your audience quickly. <a href=\"http://pingomatic.com/\">Ping-O-Matic</a> is a quick and simple way to let others know you\'ve posted new content--and ultimately drive more traffic to your blog. For self-hosted WordPress blogs, this update service is <a href=\"http://codex.wordpress.org/Update_Services\">a built-in feature</a>; you can choose the update services you would like to &#8220;ping&#8221; by going to Settings &gt; Writing in your dashboard.</p>\n<p>Need a refresher or primer? As you fill in your blog details at <a href=\"http://pingomatic.com/\">Ping-O-Matic</a>,  you can opt to ping multiple ping servers at once, such as Weblogs.com, NewsGator, Blo.gs, and FeedBurner. When you ping these services, they automatically notify subscribers that new content is posted to your website or blog.</p>\n<p>Essentially, Ping-O-Matic is a service that notifies the larger community--from search engines and blogging platforms to aggregators and social networks--of the newest, freshest content on the Internet. This, in turn, helps improve the speed at which search engines find and index <em>your</em> content.</p>\n<p>That said, driving traffic to your blog isn&#8217;t simply about enabling this service and letting it do all the work for you. Remember that getting more traffic requires more effort--posting well-written, original content in particular.</p>\n<p>To get you started, we want you to stir things up on your blog and write about a topic that&#8217;s up for debate. At <a href=\"http://dailypost.wordpress.com/\">The Daily Post</a>, we post Mind the Gap prompts that ask readers what they think about controversial and divisive issues. <strong><em>So, we\'re particularly interested in what you think about kids in adult-oriented places.</em> </strong>Most of us can agree that it\'s not a good idea to drag little Sally to a bar at 1AM, but what about a museum? A fancy restaurant?</p>\n<h2>Here are the essentials to consider when drafting this post:</h2>\n<ul>\n<li><strong>Read up on the <a href=\"http://dailypost.wordpress.com/2012/10/19/weekly-writing-challenge-children/\">existing discussion</a> of this topic: </strong>Researching this topic (and any other subject you tackle) beforehand strengthens your own stance. And it also allows you to link to related posts that enhance your discussion, as well as engage with other bloggers who have weighed in on the topic. Both are good practices and additional ways to drive the right kind of traffic to your site.</li>\n<li><strong>Pick a good, relevant title: </strong>Blog post titles are like newspaper headlines. They need to be short, snappy, and attention-grabbing. On social networks like Facebook and Twitter, your title is the primary (and may be the only) text that readers see before clicking to your post.</li>\n<li><strong><strong>Edit, proofread, and proofread some more: </strong></strong>Take the time to develop your ideas. Readers are smart--they prefer to read posts that intrigue them, make them think and question, and rouse them up. If you pique their interest, they will comment on your post thoughtfully in return.</li>\n<li><strong>Generate your own discussion: </strong>After presenting your thoughts on kids in adult-oriented places, ask questions or create your own poll at the end of your post to prompt your readers.</li>\n<li><strong>Share your stuff on social networks: </strong>Use the <a href=\"http://codex.wordpress.org/Plugins\">sharing tools available to you</a> to share this post across the Internet. Make it easy for others to spread the word.</li>\n</ul>\n<p>You can apply the process above to other posts you write. Overall, it&#8217;s important to remember that original, relevant, and well-written content is key, and from there you can share it and use the tools and services available to you to draw traffic to your blog.</p>\n<p>We look forward to providing more tips on this blog. Stay tuned!</p>\n<br />  <a rel=\"nofollow\" href=\"http://feeds.wordpress.com/1.0/gocomments/pingomatic.wordpress.com/50/\"><img alt=\"\" border=\"0\" src=\"http://feeds.wordpress.com/1.0/comments/pingomatic.wordpress.com/50/\" /></a> <img alt=\"\" border=\"0\" src=\"http://stats.wordpress.com/b.gif?host=blog.pingomatic.com&blog=68432&post=50&subd=pingomatic&ref=&feed=1\" width=\"1\" height=\"1\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 31 Oct 2012 00:18:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Cheri Lucas\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"WordPress.tv: David Tufts: The 3Cs of WordPress: A Custom Trifecta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_