nk\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"http://ma.tt/2012/10/new-jetpack/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:234:\"<p>I&#8217;m really excited abou the new Jetpack, it includes <a href=\"http://jetpack.me/2012/10/26/jetpack-1-9-toolbar-notifications/\">toolbar notifications, mobile push for iOS, a new REST API, and fixes to the contact form</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 26 Oct 2012 18:25:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:33;a:6:{s:4:\"data\";s:13:\"\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"Weblog Tools Collection: WordPress Plugin Releases for 10/26\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"http://weblogtoolscollection.com/?p=12151\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/WIGh0uTTkeI/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1575:\"<h3>New plugins</h3>\n<p><a href=\"http://wordpress.org/extend/plugins/features-by-woothemes/\"><strong>Features by WooThemes</strong></a> is a clean and easy-to-use features showcase management system.</p>\n<p><a href=\"http://blog.milandinic.com/wordpress/plugins/nav-menu-images/\"><strong>Nav Menu Images</strong></a> enables uploading of images for nav menu items on the menu edit screen.</p>\n<p><a href=\"http://wordpress.org/extend/plugins/post-via-dropbox/\"><strong>Post via Dropbox</strong></a> allows you to post or edit your blog with text files uploaded via Dropbox.</p>\n<p><a href=\"http://wordpress.org/extend/plugins/testimonials-by-woothemes/\"><strong>Testimonials by WooThemes</strong></a> is a clean and easy-to-use testimonials management system.</p>\n<h3>Updated plugins</h3>\n<p><a href=\"http://ocaoimh.ie/exploit-scanner/\"><strong>Exploit Scanner</strong></a> searches the files on your website, and the posts and comments tables of your database for anything suspicious. It also examines your list of active plugins for unusual filenames.</p>\n<p><a href=\"http://jetpack.me/\"><strong>Jetpack</strong></a> allows you to supercharge your WordPress site with powerful features previously only available to WordPress.com users.</p>\n<p><a href=\"http://wordpress.org/extend/plugins/yet-another-related-posts-plugin/\"><strong>Yet Another Related Posts Plugin</strong></a> displays a list of related entries on your site and feeds based on a unique algorithm.</p>\n<img src=\"http://feeds.feedburner.com/~r/weblogtoolscollection/UXMP/~4/WIGh0uTTkeI\" height=\"1\" width=\"1\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 26 Oct 2012 14:30:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"James\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}