INSERT INTO `wp_4kb4pz_options` VALUES("2633", "_transient_dash_aa95765b5cc111c56d5993d476b1c2f0", "<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'http://feedproxy.google.com/~r/weblogtoolscollection/UXMP/~3/fAMy_jzoF-I/\' title=\'The talented folks behind the main WordPress.org site have rolled out a new review system for plugins and themes. The new review system came from much discussion and an overall need to contextualize the star rating system. Now, if you wish to rate a plugin or a theme, you must also describe your rating decision in a brief review. The goal is that developers  [&hellip;]\'>Weblog Tools Collection: Plugin and Theme Reviews are Live on WordPress.org</a></li><li><a class=\'rsswidget\' href=\'http://wordpress.tv/2012/11/02/vasil-kolev-what-the-programmers-dont-know-and-i-wish-they-did/\' title=\' [&hellip;]\'>WordPress.tv: Vasil Kolev: What the Programmers Don\'t Know and I Wish They Did</a></li><li><a class=\'rsswidget\' href=\'http://ma.tt/2012/11/presidential-endorsements/\' title=\'It\'s interesting to read the contrast between the presidential endorsements (for Obama) from two of my favorite magazines, the New Yorker and Economist. Mayor Bloomberg was also a surprise. The Wikipedia, as always, has very comprehensive lists of endorsements for Mitt Romney and Barack Obama. [&hellip;]\'>Matt: Presidential Endorsements</a></li><li><a class=\'rsswidget\' href=\'http://wordpress.tv/2012/11/01/kalin-terziyski-the-sources-of-inspiration/\' title=\' [&hellip;]\'>WordPress.tv: Kalin Terziyski: The Sources of Inspiration</a></li><li><a class=\'rsswidget\' href=\'http://ma.tt/2012/11/building-medium-so-far/\' title=\'What I Learned Building Medium (So Far), by Evan Williams. [&hellip;]\'>Matt: Building Medium (So Far)</a></li></ul></div>", "no");
