INSERT INTO `wp_4kb4pz_posts` VALUES("142", "1", "2012-11-02 04:23:24", "2012-11-02 04:23:24", "<strong>Work:</strong> As the Print/Web Design Manager and Co-Editor/Art Director of <em>Medill Magazine</em>, I direct the visual identity for the Medill School of Journalism, Media, Integrated Marketing Communications at Northwestern University.\r\n\r\n<strong>Home:</strong> We breathe design. My husband, Jeremy Gilbert, teaches media product design at Medill and is a former art director himself. We met at The News-Press, a newspaper in my hometown of Fort Myers, Fla.\r\n\r\n<strong>Pride:</strong> Our son, Wright Brisco Gilbert.", "Jessica Parker Gilbert.", "", "publish", "closed", "closed", "", "jessica-parker-gilbert", "", "", "2012-11-02 04:23:24", "2012-11-02 04:23:24", "", "0", "http://www.jessicaparkergilbert.com/content/?post_type=boxes&#038;p=142", "10", "boxes", "", "0");
